import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{HttpRequest, StatusCodes}
import akka.http.scaladsl.model.HttpResponse
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer
import scala.concurrent.Future
import scala.util.{Failure, Success}

object WebhookProxyService extends App {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  val allowedHosts = Set("api.partner1.com", "api.partner2.com") // Add allowed hosts here

  def isValidUrl(url: String): Boolean = {
    val uri = new java.net.URI(url)
    allowedHosts.contains(uri.getHost)
  }

  val route =
    path("fetch") {
      post {
        entity(as[String]) { userUrl =>
          if (isValidUrl(userUrl)) {
            val responseFuture: Future[HttpResponse] = Http().singleRequest(HttpRequest(uri = userUrl))
            onComplete(responseFuture) {
              case Success(response) => complete(response)
              case Failure(ex) => complete(StatusCodes.InternalServerError, ex.getMessage)
            }
          } else {
            complete(StatusCodes.BadRequest, "Invalid URL")
          }
        }
      }
    }

  Http().bindAndHandle(route, "localhost", 8080)
  println("Server online at http://localhost:8080/")
}